mapper.select:
select distinct a.*
from anime a

    inner join anime_tag at on a.id = at.anime_id


    a.review_status = 'approved'

        and (a.name_cn like concat('%',#{name},'%')

            or a.name_jp like concat('%',#{name},'%')

        )


        and a.state = #{state}


        and at.tag_id = #{tagId}


order by a.id desc
